var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>2049년 12월 24일</color>","JPN":"<color=#ffd34c>2049年12月24日</color>","ENG":"<color=#ffd34c>December 24, 2049</color>","TWN":"<color=#ffd34c>2049年12月24日</color>","SCN":"<color=#ffd34c>2049年12月24日</color>","DEU":"<color=#ffd34c>December 24, 2049</color>","FRA":"<color=#ffd34c>December 24, 2049</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SCREEN_FILM","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임, 진행 중</color>","JPN":"<color=#ffd34c>クリフォトゲーム進行中</color>","ENG":"<color=#ffd34c>Qliphoth Game in progress</color>","TWN":"<color=#ffd34c>逆卡巴拉遊戲，進行中</color>","SCN":"<color=#ffd34c>神圣战役，进行中</color>","DEU":"<color=#ffd34c>Qliphoth Game in progress</color>","FRA":"<color=#ffd34c>Qliphoth Game in progress</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SCREEN_FILM","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"작전 시작 전에 브리핑 하겠습니다.","JPN":"作戦開始に先んじてブリーフィングを行います。","ENG":"We'll begin the briefing before the operation starts.","TWN":"作戰開始前進行任務說明。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이번 작전의 최우선 목표는 보름 전에 점령당한 합중국의 B17 연구 시설…….","JPN":"今回の作戦の最優先目標は、2週間前に占領された合衆国のB17研究施設……","ENG":"The main target of this operation is the B17 research facility in the States, which was overtaken 2 weeks ago...","TWN":"此次作戰的首要目標是半個月前被佔領的合眾國B17研究設施……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이곳에 보관된 고등급 아티팩트를 회수하는 것입니다.","JPN":"そこに保管されている高ランクのアーティファクトを回収すること。","ENG":"The objective is to retrieve a high-grade Artifact stored at this location.","TWN":"回收保存在此處的高級神器。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"보름 전에 점령당한 연구소라면, 4종 침식체가 출몰한 곳 말입니까?","JPN":"2週間前に占領された研究所なら、第4種侵食体が出たあの場所ではありませんか？","ENG":"Wait, the lab that was overrun two weeks ago? The one where a Category 4 C.O. appeared?","TWN":"你是說半個月前被佔領的研究所，是出現了4類侵蝕體的地方嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"무리입니다! 카운터가 포함된 부대라고 해도, 최소한 중대급 이상의 병력이 필요합니다!","JPN":"無理です！　いくらカウンターのいる部隊とはいえ、少なくとも中隊級以上の兵力が必要です！","ENG":"This is impossible! Even with a unit that includes Counters, we'll need at least a company-sized force!","TWN":"不行！即使是包含制裁者的部隊，至少也需要中隊級以上的兵力！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"겨우 이 정도 병력으로는…….","JPN":"たったこれだけの兵力では……","ENG":"With just this small a team... there's no way...","TWN":"僅憑這點兵力……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"병력이 부족한 건 사실입니다.","JPN":"兵力が足りていないのは事実です。","ENG":"We are indeed short on manpower.","TWN":"兵力不足是事實。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이번 작전은 대령님께서 양동 작전을 펼쳐 주시기로 하셨습니다.","JPN":"しかし今回の作戦は大佐自ら、陽動作戦に参加されます。","ENG":"However, the Colonel has agreed to carry out a diversionary operation.","TWN":"但是這次作戰是由上校你來展開佯攻作戰的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님께서 시설을 점거하고 있는 4종 침식체를 상대하는 동안, 우리 작전조가 시설에 침투.","JPN":"大佐が施設を占拠している第4種侵食体を相手されている間、我々作戦組が施設へ侵入。","ENG":"While the Colonel keeps the Category 4 C.O. holding the facility occupied, our squad will infiltrate.","TWN":"在上校對抗佔據設施的4類侵蝕體時，我們的作戰小組將潛入設施。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"목표 아티팩트를 회수합니다.","JPN":"ターゲットであるアーティファクトを回収します。","ENG":"And then we will retrieve the Artifact.","TWN":"回收目標人造神器。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"워커 대령님께서요……?","JPN":"ウォーカー大佐が……？","ENG":"Colonel Walker...?","TWN":"沃克上校……？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"지난 사도와의 전투에서 큰 부상을 입으셨다고 들었는데…….","JPN":"先日の使徒との戦闘で重傷を負われたと聞きましたが……","ENG":"But I heard he was seriously injured in the last battle against the Apostle...","TWN":"聽說你在上次與使徒的戰鬥中受了重傷……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……그렇습니다.","JPN":"……そうです。","ENG":"...That's correct.","TWN":"……是的。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다시 말해, 그만큼 중요한 작전이라는 뜻입니다.","JPN":"つまり、それほど重要な作戦ということです。","ENG":"In other words, that's how critical this operation is.","TWN":"換句話說，這意味著這次作戰非常重要。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니 반드시… 작전을 성공시켜야만 합니다.","JPN":"ですから必ず……作戦を成功させなければなりません。","ENG":"Which means... we must see it through to success.","TWN":"所以一定要……成功完成作戰任務。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"보고에 따르면, 연구 시설의 동력원이 살아있다고 합니다.","JPN":"報告によると、研究施設の動力源はまだ生きています。","ENG":"According to reports, the facility's power source is still operational.","TWN":"報告稱，研究設施的動力源還在運作。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"따라서 작전조는 시설에 도착하면, 최우선적으로 컨트롤 룸을 확보.","JPN":"したがって、作戦組は施設に到着し次第、最優先でコントロールルームを確保。","ENG":"Upon arrival, the squad will prioritize securing the control room.","TWN":"因此，作戰小組到達設施後，首先要確保控制室的安全。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨가 신속하게 데이터베이스에 접근하여, 아티팩트의 위치를 탐색해주세요.","JPN":"その後、シルビアさんは速やかにデータベースにアクセスし、アーティファクトの位置を探ってください。","ENG":"Sylvia, you'll access the database immediately and locate the Artifact.","TWN":"希爾維亞，請迅速訪問資料庫，搜索神器的位置。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쳇, 어쩐지 현장 타입도 아닌 나를 왜 끌고 왔나 했더니…….","JPN":"ちっ、現場向きでもないアタシを引っ張り出してきた理由はそれだったのね……","ENG":"Tch... I had a feeling. I was wondering why they needed someone like me out in the field...","TWN":"嘖，難怪把我這個非現場類型的人也帶來了……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서? 그 잘난 아티팩트가 뭐길래, 이 난리법석을 치르는 거야?","JPN":"で？　そこまでして取り返したいそのアーティファクトはいったい何なの。","ENG":"So? What's so special about this Artifact that it's worth all this chaos?","TWN":"所以呢？那個了不起的人造神器到底是什麼，竟然鬧得這麼沸沸揚揚？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"모릅니다.","JPN":"わかりません。","ENG":"We don't know.","TWN":"不知道。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"わからないですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};